  ('aboriginal-8b44517b-moex-00008', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-b6b7f9d7', 'sub-aboriginal-8b44517b-02', NULL, 'essay', '甲君與乙君均為年滿 55 歲之中高齡者，其中甲君是一位主要負擔家計
之肢體障礙者，扶養無工作收入之配偶與一位未成年子女，因為另有生
涯規劃而辭職；乙君是一般中高齡身分之主要負擔家計者，扶養無工作
收入之配偶與二位未成年子女，因公司關廠而非自願離職。二人同時經由
公立就業服務機構諮詢後，推介參加職業訓練。試述甲君與乙君符合申領
職業訓練生活津貼的「全日制」與可發給的津貼規定事項為何。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "29894f901eb7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0906", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "就業安全制度概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
